// Top-level build file where you can add configuration options common to all sub-projects/modules.
def REACT_NATIVE_VERSION = new File(['node', '--print',"JSON.parse(require('fs').readFileSync(require.resolve('react-native/package.json'), 'utf-8')).version"].execute(null, rootDir).text.trim())

buildscript {
  apply from: '../node_modules/@dynatrace/react-native-plugin/files/plugin.gradle', to: buildscript

    ext {
        buildToolsVersion = "35.0.0"
        minSdkVersion = 26
        compileSdkVersion = 35
        targetSdkVersion = 35
        supportLibVersion = "35.0.0"
        googlePlayServicesAuthVersion = "16.0.1"
        androidMapsUtilsVersion = "0.5+"
        googlePlayServicesVersion = "15.0.1"
        playServicesLocationVersion = "21.0.1"
        kotlinVersion = "1.8.10"
    // firebaseMessagingVersion = '21.1.0'
    ndkVersion = "25.1.8937393"
      cmakeVersion = "3.22.1"
    }

    repositories {
      google()
      mavenCentral()
      maven { url 'https://www.jitpack.io' }
      maven { url 'https://maven.google.com' }
      maven { url 'https://repo1.maven.org/maven2/' }
      maven { url "https://plugins.gradle.org/m2" }
      maven { url "https://mvnrepository.com/artifact/" }
      maven { url "https://android.googlesource.com/platform/prebuilts/tools/+/ac93889496c5083db47f175777c98beb3b0795aa/common/m2/repository/" }
    }
    dependencies {
      classpath("com.android.tools.build:gradle:8.6.0")
      classpath("com.facebook.react:react-native-gradle-plugin")
      classpath('com.google.gms:google-services:4.3.3')
      classpath 'com.google.firebase:firebase-crashlytics-gradle:2.9.9'
      classpath 'com.github.dcendents:android-maven-gradle-plugin:1.5'
      classpath 'com.google.firebase:perf-plugin:1.4.2'
      classpath "org.jetbrains.kotlin:kotlin-gradle-plugin:1.8.10"
      classpath "org.jetbrains.kotlin:kotlin-serialization:1.8.10"

    }
}

allprojects {
  configurations.all {
    resolutionStrategy {
      force "com.facebook.react:react-native:" + REACT_NATIVE_VERSION
    }
  }

  repositories {
    google()
    mavenCentral()
    maven { url 'https://salesforce-marketingcloud.github.io/MarketingCloudSDK-Android/repository' }
    mavenLocal()
    maven { url 'https://www.jitpack.io' }
    maven { url 'https://maven.google.com' }
    maven { url 'https://repo1.maven.org/maven2/' }
    maven { url "https://plugins.gradle.org/m2" }
    maven { url "https://mvnrepository.com/artifact/" }
    maven { url "https://s3.amazonaws.com/inapp.salesforce.com/public/android" }
    maven { url "https://android.googlesource.com/platform/prebuilts/tools/+/ac93889496c5083db47f175777c98beb3b0795aa/common/m2/repository/" }
    maven { url 'https://s3.amazonaws.com/salesforcesos.com/android/maven/release' }
    flatDir {
        dirs 'libs', "$rootDir/../node_modules/@semparar/mf-app-fraudprevention/android/libs"
    }

    maven {
      // All of React Native (JS, Obj-C sources, Android binaries) is installed from npm
      url("$rootDir/../node_modules/react-native/android")
    }

    maven {
      // Android JSC is installed from npm
      url("$rootDir/../node_modules/jsc-android/dist")
    }

    maven {
      // Unico SDK
      url 'https://maven-sdk.unico.run/sdk-mobile'
    }

    flatDir {
      dirs 'libs', "$rootDir/../node_modules/@semparar/mf-app-fraudprevention/android/libs"
    }
  }
}

